import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Menu, X, LogOut } from 'lucide-react';
import { useAuthStore, useNavigationStore } from '@/stores';

export const Navbar: React.FC = () => {
    const { user, isAuthenticated, logout } = useAuthStore();
    const { isMenuOpen, toggleMenu } = useNavigationStore();
    const location = useLocation();
    const navigate = useNavigate();

    const navLinkClasses = (path: string, isHashLink = false) => {
        const isActive = isHashLink
            ? location.pathname === '/' && location.hash === path
            : location.pathname === path;
        return isActive
            ? 'text-primry font-bold border-b-2 border-primary pb-1 font-headline tracking-tight transition-all duration-300'
            : 'text-slate-500 font-medium hover:text-primary font-headline tracking-tight hover:opacity-80 transition-all duration-300';
    };

    const handleLogout = () => {
        logout();
        if (isMenuOpen) {
            toggleMenu();
        }
        navigate('/');
    };

    return (
        <nav className="bg-white text-primary! backdrop-blur-xl fixed top-0 w-full z-50 transition-all duration-300">
            <div className="max-w-7xl mx-auto px-8 h-20 flex justify-between items-center">
                <div className="flex items-center gap-12">
                    <Link
                        to="/"
                        className="text-xl font-extrabold tracking-tighter text-primary font-headline"
                    >
                        Dream Well Ventures
                    </Link>
                    <div className="hidden md:flex gap-8">
                        <Link
                            to="/"
                            className={navLinkClasses('/')}
                        >
                            Listings
                        </Link>
                        <Link
                            to="/#marketing"
                            className={navLinkClasses('#marketing', true)}
                        >
                            Marketing
                        </Link>
                        <Link
                            to="/#insights"
                            className={navLinkClasses('#insights', true)}
                        >
                            Insights
                        </Link>
                        {isAuthenticated && user?.role === 'admin' && (
                            <Link
                                to="/admin"
                                className={navLinkClasses('/admin')}
                            >
                                Admin
                            </Link>
                        )}
                        {isAuthenticated && (
                            <Link
                                to="/profile"
                                className={navLinkClasses('/profile')}
                            >
                                Portfolio
                            </Link>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-6">
                    {!isAuthenticated ? (
                        <>
                            <Link
                                to="/authorize"
                                className="px-6 py-2 border border-primary text-primary rounded-xl font-semibold text-sm hover:bg-primary hover:text-on-primary transition-all active:scale-95"
                            >
                                Sign In
                            </Link>
                        </>
                    ) : (
                        <>
                            <div className="flex items-center gap-4">
                                <Link
                                    to="/profile"
                                    className="flex items-center gap-3 rounded-full border border-surface-variant px-2 py-1 hover:border-primary/40 transition-all"
                                >
                                    {user?.avatar ? (
                                        <img
                                            alt="User avatar"
                                            className="w-10 h-10 rounded-full object-cover ring-2 ring-primary/20"
                                            src={user.avatar}
                                        />
                                    ) : (
                                        <div className="w-10 h-10 rounded-full bg-surface-container-high flex items-center justify-center text-primary font-bold ring-2 ring-primary/20">
                                            {user?.name?.charAt(0)}
                                        </div>
                                    )}
                                    <span className="hidden md:block text-sm font-semibold text-primary">
                                        {user?.name}
                                    </span>
                                </Link>
                                <button
                                    onClick={handleLogout}
                                    className="hidden lg:flex items-center gap-2 text-sm font-semibold text-slate-500 hover:text-primary transition-all"
                                >
                                    <LogOut className="w-4 h-4" />
                                    Sign Out
                                </button>
                            </div>
                        </>
                    )}

                    {/* Mobile menu button */}
                    <button
                        className="md:hidden p-2"
                        onClick={toggleMenu}
                    >
                        {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
                    </button>
                </div>
            </div>

            {/* Mobile menu */}
            {isMenuOpen && (
                <div className="md:hidden bg-surface-container-lowest border-t border-surface-variant">
                    <div className="max-w-7xl mx-auto px-8 py-6 space-y-4">
                        <Link
                            to="/"
                            className={`block font-headline ${location.pathname === '/' && !location.hash ? 'text-primary font-bold' : 'text-slate-500 font-medium'}`}
                            onClick={toggleMenu}
                        >
                            Listings
                        </Link>
                        <Link
                            to="/#marketing"
                            className={`block font-headline ${location.pathname === '/' && location.hash === '#marketing' ? 'text-primary font-bold' : 'text-slate-500 font-medium'}`}
                            onClick={toggleMenu}
                        >
                            Marketing
                        </Link>
                        <Link
                            to="/#insights"
                            className={`block font-headline ${location.pathname === '/' && location.hash === '#insights' ? 'text-primary font-bold' : 'text-slate-500 font-medium'}`}
                            onClick={toggleMenu}
                        >
                            Insights
                        </Link>
                        {isAuthenticated && user?.role === 'admin' && (
                            <Link
                                to="/admin"
                                className={`block font-headline ${location.pathname === '/admin' ? 'text-primary font-bold' : 'text-slate-500 font-medium'}`}
                                onClick={toggleMenu}
                            >
                                Admin
                            </Link>
                        )}
                        {isAuthenticated && (
                            <Link
                                to="/profile"
                                className={`block font-headline ${location.pathname === '/profile' ? 'text-primary font-bold' : 'text-slate-500 font-medium'}`}
                                onClick={toggleMenu}
                            >
                                Portfolio
                            </Link>
                        )}
                        {isAuthenticated ? (
                            <button
                                onClick={handleLogout}
                                className="block w-full text-left text-red-600 font-medium font-headline"
                            >
                                Sign Out
                            </button>
                        ) : (
                            <Link
                                to="/authorize"
                                className="block text-primary font-bold font-headline"
                                onClick={toggleMenu}
                            >
                                Sign In
                            </Link>
                        )}
                    </div>
                </div>
            )}
        </nav>
    );
};
