import React, { useState } from 'react';
import { Link } from 'react-router-dom';

export const ForgotPasswordPage: React.FC = () => {
  const [email, setEmail] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
  };

  return (
    <main className="min-h-screen flex items-center justify-center pt-24 pb-16">
      <div className="w-full max-w-md bg-surface-container-lowest rounded-xl p-8 shadow-sm">
        <h1 className="text-3xl font-extrabold text-primary mb-2 font-headline">
          Reset your password
        </h1>
        <p className="text-on-surface-variant mb-8">
          Enter your email and we will send reset instructions.
        </p>

        {submitted ? (
          <div className="bg-tertiary-fixed-dim text-primary p-4 rounded-xl text-sm font-semibold">
            If an account exists for {email}, reset instructions have been sent.
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-xs font-bold uppercase tracking-widest text-on-surface-variant mb-2" htmlFor="reset-email">
                Email Address
              </label>
              <input
                id="reset-email"
                type="email"
                className="w-full bg-surface-container-lowest border-none focus:ring-2 focus:ring-primary-fixed-dim rounded-xl p-4 text-on-surface placeholder:text-slate-400 text-sm"
                placeholder="name@dreamwell.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>
            <button
              type="submit"
              className="w-full bg-primary text-on-primary py-4 rounded-xl font-bold tracking-tight shadow-lg shadow-primary/20 hover:opacity-90 transition-all active:scale-[0.98]"
            >
              Send Reset Link
            </button>
          </form>
        )}

        <div className="mt-8 text-center">
          <Link className="text-sm font-bold text-primary hover:underline underline-offset-4" to="/authorize">
            Back to Sign In
          </Link>
        </div>
      </div>
    </main>
  );
};
