import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuthStore } from '@/stores';

export const RegisterPage: React.FC = () => {
  const navigate = useNavigate();
  const { register, isLoading } = useAuthStore();
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
  });
  const [error, setError] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
    if (error) {
      setError('');
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.password) {
      setError('Please complete all required fields.');
      return;
    }
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match.');
      return;
    }

    try {
      await register({
        name: formData.name,
        email: formData.email,
        role: 'user',
      });
      navigate('/profile');
    } catch (err) {
      setError('Registration failed. Please try again.');
    }
  };

  return (
    <main className="min-h-screen flex items-center justify-center pt-24 pb-16">
      <div className="w-full max-w-md bg-surface-container-lowest rounded-xl p-8 shadow-sm">
        <h1 className="text-3xl font-extrabold text-primary mb-2 font-headline">Create your account</h1>
        <p className="text-on-surface-variant mb-8">
          Join our plotted community updates and access premium listings.
        </p>

        {error && (
          <div className="bg-error-container text-on-error-container p-3 rounded-xl text-sm mb-6">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-xs font-bold uppercase tracking-widest text-on-surface-variant mb-2" htmlFor="name">
              Full Name
            </label>
            <input
              id="name"
              name="name"
              type="text"
              className="w-full bg-surface-container-lowest border-none focus:ring-2 focus:ring-primary-fixed-dim rounded-xl p-4 text-on-surface placeholder:text-slate-400 text-sm"
              placeholder="Your name"
              value={formData.name}
              onChange={handleChange}
              required
            />
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-widest text-on-surface-variant mb-2" htmlFor="email">
              Email Address
            </label>
            <input
              id="email"
              name="email"
              type="email"
              className="w-full bg-surface-container-lowest border-none focus:ring-2 focus:ring-primary-fixed-dim rounded-xl p-4 text-on-surface placeholder:text-slate-400 text-sm"
              placeholder="name@dreamwell.com"
              value={formData.email}
              onChange={handleChange}
              required
            />
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-widest text-on-surface-variant mb-2" htmlFor="password">
              Password
            </label>
            <input
              id="password"
              name="password"
              type="password"
              className="w-full bg-surface-container-lowest border-none focus:ring-2 focus:ring-primary-fixed-dim rounded-xl p-4 text-on-surface placeholder:text-slate-400 text-sm"
              placeholder="••••••••"
              value={formData.password}
              onChange={handleChange}
              required
            />
          </div>

          <div>
            <label className="block text-xs font-bold uppercase tracking-widest text-on-surface-variant mb-2" htmlFor="confirmPassword">
              Confirm Password
            </label>
            <input
              id="confirmPassword"
              name="confirmPassword"
              type="password"
              className="w-full bg-surface-container-lowest border-none focus:ring-2 focus:ring-primary-fixed-dim rounded-xl p-4 text-on-surface placeholder:text-slate-400 text-sm"
              placeholder="••••••••"
              value={formData.confirmPassword}
              onChange={handleChange}
              required
            />
          </div>

          <button
            type="submit"
            className="w-full bg-primary text-on-primary py-4 rounded-xl font-bold tracking-tight shadow-lg shadow-primary/20 hover:opacity-90 transition-all active:scale-[0.98] disabled:opacity-50"
            disabled={isLoading}
          >
            {isLoading ? 'Creating Account...' : 'Create Account'}
          </button>
        </form>

        <div className="mt-8 text-center">
          <span className="text-sm text-on-surface-variant">Already have an account?</span>
          <Link className="text-sm font-bold text-primary hover:underline underline-offset-4 ml-1" to="/authorize">
            Sign in
          </Link>
        </div>
      </div>
    </main>
  );
};
