import React, { useEffect, useState } from 'react';
import { MessageSquare, X } from 'lucide-react';
import { useChatStore } from '@/stores';

export const ChatWidget: React.FC = () => {
    const { messages, isOpen, sendMessage, toggleChat, autoCollapse } = useChatStore();
    const [input, setInput] = useState('');

    useEffect(() => {
        const timer = setTimeout(() => {
            autoCollapse();
        }, 3000);

        return () => clearTimeout(timer);
    }, [autoCollapse]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;
        sendMessage(input.trim());
        setInput('');
    };

    return (
        <div className="fixed bottom-6 right-6 z-50 w-80">
            {isOpen ?
                <div className={`bg-primary text-on-primary rounded-2xl shadow-xl overflow-hidden transition-all duration-300 ${isOpen ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
                    <div className="flex items-center justify-between px-4 py-3 border-b border-surface-variant">
                        <div>
                            <p className="text-sm font-bold">Dream Well Live</p>
                            <p className="text-xs text-white/70">Project assistance</p>
                        </div>
                        <button onClick={toggleChat} className="p-2 rounded-full hover:bg-primary/10 transition">
                            <X className="w-4 h-4" />
                        </button>
                    </div>
                    <div className="max-h-64 overflow-y-auto p-4 space-y-3">
                        {messages.map((message) => (
                            <div
                                key={message.id}
                                className={`rounded-xl px-3 py-2 text-sm ${message.sender === 'user' ? 'bg-primary/10 text-white ml-10' : 'bg-secondary/10 text-white mr-10'}`}
                            >
                                {message.content}
                            </div>
                        ))}
                    </div>
                    <form onSubmit={handleSubmit} className="p-4 border-t border-surface-variant flex gap-2">
                        <input
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            className="flex-1 bg-primary/5 border border-primary/20 rounded-xl px-3 py-2 text-sm text-white placeholder:text-white/50 focus:ring-2 focus:ring-tertiary-fixed-dim"
                            placeholder="Type your message..."
                        />
                        <button
                            type="submit"
                            className="bg-tertiary-fixed-dim text-primary px-4 rounded-xl text-sm font-bold"
                        >
                            Send
                        </button>
                    </form>
                </div>
                : null}

            <button
                onClick={toggleChat}
                className={`mt-3 w-full flex items-center justify-center gap-2 bg-surface text-on-surface rounded-full px-4 py-3 shadow-lg font-semibold transition ${isOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}
            >
                <MessageSquare className="w-4 h-4" />
                Chat with us
            </button>
        </div>
    );
};
