import { create } from 'zustand';

interface ChatMessage {
  id: string;
  sender: 'user' | 'system';
  content: string;
  timestamp: Date;
}

interface ChatState {
  messages: ChatMessage[];
  isOpen: boolean;
  hasAutoCollapsed: boolean;
  sendMessage: (content: string) => void;
  toggleChat: () => void;
  autoCollapse: () => void;
}

const systemReplies = [
  'Thanks for reaching out. A project advisor will connect with you shortly.',
  'We can arrange a site visit and share the latest plot availability.',
  'Would you like a brochure or the price sheet first?',
];

export const useChatStore = create<ChatState>((set, get) => ({
  messages: [
    {
      id: 'system-1',
      sender: 'system',
      content: 'Hello! Looking for premium plots in Porur? Ask us anything.',
      timestamp: new Date(),
    },
  ],
  isOpen: true,
  hasAutoCollapsed: false,
  sendMessage: (content: string) => {
    const newMessage: ChatMessage = {
      id: `user-${Date.now()}`,
      sender: 'user',
      content,
      timestamp: new Date(),
    };

    const systemMessage: ChatMessage = {
      id: `system-${Date.now()}-reply`,
      sender: 'system',
      content: systemReplies[Math.floor(Math.random() * systemReplies.length)],
      timestamp: new Date(),
    };

    set((state) => ({
      messages: [...state.messages, newMessage, systemMessage],
    }));
  },
  toggleChat: () => {
    const { isOpen } = get();
    set({ isOpen: !isOpen });
  },
  autoCollapse: () => {
    const { hasAutoCollapsed } = get();
    if (!hasAutoCollapsed) {
      set({ isOpen: false, hasAutoCollapsed: true });
    }
  },
}));
