import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuthStore } from '@/stores';
import { LoginForm, FormErrors } from '@/types';

export const LoginSection: React.FC = () => {
    const navigate = useNavigate();
    const { login, isLoading } = useAuthStore();
    const [formData, setFormData] = useState<LoginForm>({
        email: '',
        password: '',
        rememberMe: false,
    });
    const [errors, setErrors] = useState<FormErrors>({});

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value, type, checked } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: type === 'checkbox' ? checked : value,
        }));

        // Clear error when user starts typing
        if (errors[name]) {
            setErrors(prev => ({ ...prev, [name]: '' }));
        }
    };

    const validateForm = (): boolean => {
        const newErrors: FormErrors = {};

        if (!formData.email) {
            newErrors.email = 'Email is required';
        } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
            newErrors.email = 'Please enter a valid email';
        }

        if (!formData.password) {
            newErrors.password = 'Password is required';
        } else if (formData.password.length < 6) {
            newErrors.password = 'Password must be at least 6 characters';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!validateForm()) return;

        try {
            await login(formData.email, formData.password);
            const currentUser = useAuthStore.getState().user;
            navigate(currentUser?.role === 'admin' ? '/admin' : '/profile');
        } catch (error) {
            setErrors({ general: 'Invalid email or password' });
        }
    };

    return (
        <div className="w-full max-w-md">
            <div className="mb-10">
                <h2 className="text-3xl font-extrabold text-primary tracking-tight mb-2 font-headline">
                    Welcome Back
                </h2>
                <p className="text-on-surface-variant font-medium">
                    Continue your journey in luxury real estate.
                </p>
            </div>

            {/* Login Form */}
            <form onSubmit={handleSubmit} className="space-y-6">
                {errors.general && (
                    <div className="bg-error-container text-on-error-container p-3 rounded-xl text-sm">
                        {errors.general}
                    </div>
                )}

                <div>
                    <label
                        className="block text-xs font-bold uppercase tracking-widest text-on-surface-variant mb-2"
                        htmlFor="email"
                    >
                        Email Address
                    </label>
                    <input
                        className={`w-full bg-surface-container-lowest border-none focus:ring-2 rounded-xl p-4 text-on-surface placeholder:text-slate-400 text-sm transition-all ${errors.email
                            ? 'focus:ring-error ring-1 ring-error'
                            : 'focus:ring-primary-fixed-dim'
                            }`}
                        id="email"
                        name="email"
                        placeholder="name@dreamwell.com"
                        type="email"
                        value={formData.email}
                        onChange={handleChange}
                        required
                    />
                    {errors.email && (
                        <p className="text-error text-xs mt-1">{errors.email}</p>
                    )}
                </div>

                <div>
                    <div className="flex justify-between mb-2">
                        <label
                            className="block text-xs font-bold uppercase tracking-widest text-on-surface-variant"
                            htmlFor="password"
                        >
                            Password
                        </label>
                        <Link
                            className="text-xs font-bold text-primary hover:underline underline-offset-4"
                            to="/forgot-password"
                        >
                            Forgot?
                        </Link>
                    </div>
                    <input
                        className={`w-full bg-surface-container-lowest border-none focus:ring-2 rounded-xl p-4 text-on-surface placeholder:text-slate-400 text-sm transition-all ${errors.password
                            ? 'focus:ring-error ring-1 ring-error'
                            : 'focus:ring-primary-fixed-dim'
                            }`}
                        id="password"
                        name="password"
                        placeholder="••••••••"
                        type="password"
                        value={formData.password}
                        onChange={handleChange}
                        required
                    />
                    {errors.password && (
                        <p className="text-error text-xs mt-1">{errors.password}</p>
                    )}
                </div>

                <div className="flex items-center gap-3 py-2">
                    <input
                        className="w-5 h-5 rounded border-none bg-surface-container-highest text-primary focus:ring-0"
                        id="rememberMe"
                        name="rememberMe"
                        type="checkbox"
                        checked={formData.rememberMe}
                        onChange={handleChange}
                    />
                    <label className="text-sm text-on-surface-variant font-medium" htmlFor="rememberMe">
                        Keep me signed in for 30 days
                    </label>
                </div>

                <button
                    className="w-full bg-primary text-on-primary py-4 rounded-xl font-bold tracking-tight shadow-lg shadow-primary/20 hover:opacity-90 transition-all active:scale-[0.98] mt-4 disabled:opacity-50 disabled:cursor-not-allowed"
                    type="submit"
                    disabled={isLoading}
                >
                    {isLoading ? 'Signing In...' : 'Access Dream Well'}
                </button>
            </form>

            <div className="mt-12 pt-8 border-t border-outline-variant text-center">
                <p className="text-sm text-on-surface-variant font-medium">
                    Don't have an account?
                    <Link
                        className="text-primary font-bold hover:underline underline-offset-4 ml-1"
                        to="/register"
                    >
                        Create an Identity
                    </Link>
                </p>
            </div>
        </div>
    );
};
