import React from 'react';
import { Link } from 'react-router-dom';
import { mockProperties } from '@/data/mockData';

export const ProjectsPage: React.FC = () => {
  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(price * 83);
  };

  return (
    <main className="min-h-screen pt-24 pb-16 bg-surface-container-low">
      <div className="max-w-7xl mx-auto px-8">
        <div className="flex flex-col md:flex-row justify-between items-end gap-8 mb-12">
          <div>
            <p className="text-xs uppercase tracking-[0.2em] text-on-primary-container font-bold mb-3">
              Plotted Communities
            </p>
            <h1 className="text-4xl md:text-5xl font-extrabold text-white font-headline">
              All Projects
            </h1>
          </div>
          <Link
            to="/"
            className="text-white font-semibold hover:underline underline-offset-4"
          >
            Back to Home
          </Link>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {mockProperties.map((property) => (
            <Link
              key={property.id}
              to={`/property/${property.id}`}
              className="bg-surface-container-lowest rounded-xl overflow-hidden shadow-sm hover:shadow-md transition-shadow"
            >
              <div className="h-56 overflow-hidden">
                <img
                  alt={property.title}
                  className="w-full h-full object-cover"
                  src={property.images[0]}
                />
              </div>
              <div className="p-6">
                <p className="text-xs uppercase tracking-widest text-on-surface-variant font-semibold mb-2">
                  {property.location}
                </p>
                <h3 className="text-xl font-bold text-white font-headline mb-3">
                  {property.title}
                </h3>
                <p className="text-sm text-on-surface-variant mb-4">
                  {property.description}
                </p>
                <div className="flex items-center justify-between">
                  <span className="text-sm font-semibold text-white">
                    {property.area.toLocaleString()} sq.ft
                  </span>
                  <span className="text-sm font-bold text-white">
                    {formatPrice(property.price)}
                  </span>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </main>
  );
};
