import React, { useState, useMemo } from 'react';
import {
  useReactTable,
  getCoreRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  flexRender,
  ColumnDef,
  SortingState,
  ColumnFiltersState,
} from '@tanstack/react-table';
import { Search, Eye, Edit, Trash2, Plus, ChevronLeft, ChevronRight } from 'lucide-react';
import { mockProperties } from '@/data/mockData';
import { Property } from '@/types';

export const AdminPage: React.FC = () => {
  const [data, setData] = useState(mockProperties);
  const [sorting, setSorting] = useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);
  const [globalFilter, setGlobalFilter] = useState('');

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(price * 83);
  };

  const formatArea = (area: number) => {
    return `${area.toLocaleString()} sq ft`;
  };

  const handleAddProperty = () => {
    const id = `new-${Date.now()}`;
    const newProperty: Property = {
      id,
      title: 'Porur Crest Plots',
      description: 'Premium gated plots with strong connectivity and ready-to-construct layouts.',
      price: 1650000,
      location: 'Porur, Chennai',
      bedrooms: 0,
      bathrooms: 0,
      area: 900,
      type: 'residential',
      status: 'available',
      images: [
        'https://lh3.googleusercontent.com/aida-public/AB6AXuBGMmIYtw6CekvzrDZ_wA158rBHTgz3jApGNPPusfDRLKuhAXnrJlmK5z3WWYULvozy9IjXgSdvBM8X34PZBw8tSjQhyFJPPie71E1yNQJiZAR5odNfNL-5xpBuuFjsLxqM9aH8cz3ZAYO-JJwutTj_MVstZHjPvGUlHDnpoITkIJ5A_eOQc-tm6sPZ8jsc-XFtCDTWxzdn0oTgbCRiFRi9tKBdjm2Zbc_ooQUyVeX_YcXnfCrRVf7ilysQLlWLAOUkNK9XxXFtuw'
      ],
      features: ['Ready to construct', 'Gated community', 'Internal roads', 'CCTV surveillance'],
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    setData((prev) => [newProperty, ...prev]);
  };

  const handleViewProperty = (propertyId: string) => {
    window.location.href = `/property/${propertyId}`;
  };

  const handleEditProperty = (propertyId: string) => {
    setData((prev) =>
      prev.map((property) =>
        property.id === propertyId
          ? {
              ...property,
              title: `${property.title} (Updated)`,
              status: property.status === 'available' ? 'pending' : 'available',
              updatedAt: new Date(),
            }
          : property
      )
    );
  };

  const handleDeleteProperty = (propertyId: string) => {
    setData((prev) => prev.filter((property) => property.id !== propertyId));
  };

  const columns = useMemo<ColumnDef<Property>[]>(
    () => [
      {
        accessorKey: 'title',
        header: 'Property',
        cell: (info) => (
          <div className="flex items-center gap-3">
            <img
              src={info.row.original.images[0]}
              alt={info.getValue() as string}
              className="w-12 h-12 rounded-lg object-cover"
            />
            <div>
              <div className="font-semibold text-primary">{info.getValue() as string}</div>
              <div className="text-sm text-on-surface-variant">{info.row.original.location}</div>
            </div>
          </div>
        ),
      },
      {
        accessorKey: 'price',
        header: 'Price',
        cell: (info) => (
          <span className="font-bold text-primary">{formatPrice(info.getValue() as number)}</span>
        ),
      },
      {
        accessorKey: 'area',
        header: 'Area',
        cell: (info) => formatArea(info.getValue() as number),
      },
      {
        accessorKey: 'bedrooms',
        header: 'Bed/Bath',
        cell: (info) => `${info.getValue() as number}/${info.row.original.bathrooms}`,
      },
      {
        accessorKey: 'type',
        header: 'Type',
        cell: (info) => (
          <span className="capitalize text-sm px-2 py-1 bg-surface-container rounded-full">
            {info.getValue() as string}
          </span>
        ),
      },
      {
        accessorKey: 'status',
        header: 'Status',
        cell: (info) => {
          const status = info.getValue() as string;
          const statusColors: Record<string, string> = {
            available: 'bg-tertiary-fixed-dim text-on-tertiary-container',
            pending: 'bg-secondary-container text-on-secondary-container',
            sold: 'bg-surface-container-high text-on-surface',
          };
          return (
            <span className={`capitalize text-xs px-3 py-1 rounded-full font-semibold ${statusColors[status]}`}>
              {status}
            </span>
          );
        },
      },
      {
        id: 'actions',
        header: 'Actions',
        cell: ({ row }) => (
          <div className="flex items-center gap-2">
            <button
              className="p-2 hover:bg-surface-container rounded-lg transition-colors cursor-pointer"
              onClick={() => handleViewProperty(row.original.id)}
              aria-label="View property"
            >
              <Eye className="w-4 h-4 text-primary" />
            </button>
            <button
              className="p-2 hover:bg-surface-container rounded-lg transition-colors cursor-pointer"
              onClick={() => handleEditProperty(row.original.id)}
              aria-label="Edit property"
            >
              <Edit className="w-4 h-4 text-secondary" />
            </button>
            <button
              className="p-2 hover:bg-error-container rounded-lg transition-colors cursor-pointer"
              onClick={() => handleDeleteProperty(row.original.id)}
              aria-label="Delete property"
            >
              <Trash2 className="w-4 h-4 text-error" />
            </button>
          </div>
        ),
      },
    ],
    []
  );

  const table = useReactTable({
    data,
    columns,
    state: {
      sorting,
      columnFilters,
      globalFilter,
    },
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onGlobalFilterChange: setGlobalFilter,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
  });

  return (
    <main className="min-h-screen pt-24 pb-16">
      <div className="max-w-7xl mx-auto px-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-4xl font-extrabold font-headline text-primary mb-2">
            Property Management
          </h1>
          <p className="text-on-surface-variant">
            Manage your property portfolio and listings
          </p>
        </div>

        {/* Controls */}
        <div className="bg-surface-container-lowest rounded-xl p-6 mb-8">
          <div className="flex flex-col md:flex-row gap-4 justify-between items-start md:items-center">
            <div className="flex-1 max-w-md">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-outline" />
                <input
                  type="text"
                  placeholder="Search properties..."
                  className="w-full pl-10 pr-4 py-3 bg-surface-container border-none rounded-xl focus:ring-2 focus:ring-primary-fixed-dim"
                  value={globalFilter ?? ''}
                  onChange={(e) => setGlobalFilter(e.target.value)}
                />
              </div>
            </div>
            
            <div className="flex gap-3">
              <select
                className="px-4 py-3 bg-surface-container border-none rounded-xl focus:ring-2 focus:ring-primary-fixed-dim"
                onChange={(e) => {
                  table.getColumn('status')?.setFilterValue(e.target.value || undefined);
                }}
              >
                <option value="">All Status</option>
                <option value="available">Available</option>
                <option value="pending">Pending</option>
                <option value="sold">Sold</option>
              </select>
              
              <button
                onClick={handleAddProperty}
                className="bg-primary text-on-primary px-6 py-3 rounded-xl font-semibold flex items-center gap-2 hover:opacity-90 transition-all cursor-pointer"
              >
                <Plus className="w-4 h-4" />
                Add Property
              </button>
            </div>
          </div>
        </div>

        {/* Table */}
        <div className="bg-surface-container-lowest rounded-xl overflow-hidden shadow-sm">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-surface-container-high">
                {table.getHeaderGroups().map((headerGroup) => (
                  <tr key={headerGroup.id}>
                    {headerGroup.headers.map((header) => (
                      <th
                        key={header.id}
                        className="px-6 py-4 text-left text-xs font-bold uppercase tracking-widest text-on-surface-variant"
                      >
                        {header.isPlaceholder ? null : (
                          <div
                            className={
                              header.column.getCanSort()
                                ? 'cursor-pointer select-none flex items-center gap-2 hover:text-on-surface transition-colors'
                                : ''
                            }
                            onClick={header.column.getToggleSortingHandler()}
                          >
                            {flexRender(header.column.columnDef.header, header.getContext())}
                            {{
                              asc: ' ↑',
                              desc: ' ↓',
                            }[header.column.getIsSorted() as string] ?? null}
                          </div>
                        )}
                      </th>
                    ))}
                  </tr>
                ))}
              </thead>
              <tbody>
                {table.getRowModel().rows.map((row) => (
                  <tr
                    key={row.id}
                    className="border-b border-surface-variant hover:bg-surface-container-low transition-colors"
                  >
                    {row.getVisibleCells().map((cell) => (
                      <td key={cell.id} className="px-6 py-4">
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Pagination */}
          <div className="px-6 py-4 border-t border-surface-variant flex items-center justify-between">
            <div className="text-sm text-on-surface-variant">
              Showing {table.getState().pagination.pageIndex * table.getState().pagination.pageSize + 1} to{' '}
              {Math.min(
                (table.getState().pagination.pageIndex + 1) * table.getState().pagination.pageSize,
                table.getFilteredRowModel().rows.length
              )}{' '}
              of {table.getFilteredRowModel().rows.length} properties
            </div>
            
            <div className="flex items-center gap-2">
              <button
                className="p-2 rounded-lg hover:bg-surface-container transition-colors disabled:opacity-50"
                onClick={() => table.previousPage()}
                disabled={!table.getCanPreviousPage()}
              >
                <ChevronLeft className="w-4 h-4" />
              </button>
              
              <span className="text-sm font-medium px-3 py-2">
                {table.getState().pagination.pageIndex + 1} of {table.getPageCount()}
              </span>
              
              <button
                className="p-2 rounded-lg hover:bg-surface-container transition-colors disabled:opacity-50"
                onClick={() => table.nextPage()}
                disabled={!table.getCanNextPage()}
              >
                <ChevronRight className="w-4 h-4" />
              </button>
            </div>
          </div>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mt-8">
          <div className="bg-surface-container-lowest p-6 rounded-xl">
            <h3 className="text-sm font-bold uppercase tracking-widest text-on-surface-variant mb-2">
              Total Properties
            </h3>
            <p className="text-3xl font-extrabold text-primary">{data.length}</p>
          </div>
          
          <div className="bg-surface-container-lowest p-6 rounded-xl">
            <h3 className="text-sm font-bold uppercase tracking-widest text-on-surface-variant mb-2">
              Available
            </h3>
            <p className="text-3xl font-extrabold text-tertiary-fixed-dim">
              {data.filter(p => p.status === 'available').length}
            </p>
          </div>
          
          <div className="bg-surface-container-lowest p-6 rounded-xl">
            <h3 className="text-sm font-bold uppercase tracking-widest text-on-surface-variant mb-2">
              Pending
            </h3>
            <p className="text-3xl font-extrabold text-secondary">
              {data.filter(p => p.status === 'pending').length}
            </p>
          </div>
          
          <div className="bg-surface-container-lowest p-6 rounded-xl">
            <h3 className="text-sm font-bold uppercase tracking-widest text-on-surface-variant mb-2">
              Total Value
            </h3>
            <p className="text-3xl font-extrabold text-primary">
              {formatPrice(data.reduce((sum, p) => sum + p.price, 0))}
            </p>
          </div>
        </div>
      </div>
    </main>
  );
};
