import React, { useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import { Navbar, Footer } from '@/components/layout';
import { ProtectedRoute } from '@/components/common';
import { HomePage, AuthorizePage, PropertyDetailsPage, AdminPage, ProfilePage, ForgotPasswordPage, RegisterPage, ProjectsPage } from '@/pages';
import { useNavigationStore } from '@/stores';

const AppContent: React.FC = () => {
  const location = useLocation();
  const { setCurrentPath } = useNavigationStore();

  useEffect(() => {
    setCurrentPath(location.pathname);
  }, [location.pathname, setCurrentPath]);

  useEffect(() => {
    if (location.hash) {
      const targetId = location.hash.replace('#', '');
      const element = document.getElementById(targetId);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    }
  }, [location.hash]);

  // Don't show navbar and footer on auth page
  const isAuthPage = location.pathname === '/authorize';

  return (
    <div className="min-h-screen bg-background flex flex-col">
      {!isAuthPage && <Navbar />}
      <div className={`flex-grow ${!isAuthPage ? 'pt-20' : ''}`}>
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/authorize" element={<AuthorizePage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/forgot-password" element={<ForgotPasswordPage />} />
          <Route path="/projects" element={<ProjectsPage />} />
          <Route 
            path="/property/:id" 
            element={
              <ProtectedRoute requireAuth={false}>
                <PropertyDetailsPage />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/profile" 
            element={
              <ProtectedRoute requireAuth={true}>
                <ProfilePage />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="/admin" 
            element={
              <ProtectedRoute requireAuth={true} requireAdmin={true}>
                <AdminPage />
              </ProtectedRoute>
            } 
          />
          <Route 
            path="*" 
            element={
              <div className="min-h-screen flex items-center justify-center">
                <div className="text-center">
                  <h1 className="text-4xl font-bold font-headline text-white mb-4">404</h1>
                  <p className="text-on-surface-variant">Page not found</p>
                </div>
              </div>
            } 
          />
        </Routes>
      </div>
      {!isAuthPage && <Footer />}
    </div>
  );
};

function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}

export default App;
