import { create } from 'zustand';
import { AuthState, User } from '@/types';
import { mockUsers } from '@/data/mockData';

export const useAuthStore = create<AuthState>((set) => ({
    user: null,
    isAuthenticated: false,
    isLoading: false,

    login: async (email: string, password: string) => {
        set({ isLoading: true });

        try {
            // Simulate API call
            await new Promise(resolve => setTimeout(resolve, 1000));

            // Simple mock authentication
            if (email === 'julian@dreamwell.com' && password === 'password') {
                const user = mockUsers[0];
                set({
                    user,
                    isAuthenticated: true,
                    isLoading: false,
                });
                localStorage.setItem('auth-user', JSON.stringify(user));
            } else if (email === 'admin@dreamwell.com' && password === 'admin@123') {
                const adminUser: User = {
                    id: 'admin-1',
                    name: 'Admin User',
                    email: 'admin@dreamwell.com',
                    role: 'admin',
                    createdAt: new Date()
                };
                set({
                    user: adminUser,
                    isAuthenticated: true,
                    isLoading: false,
                });
                localStorage.setItem('auth-user', JSON.stringify(adminUser));
            } else {
                set({ isLoading: false });
                throw new Error('Invalid credentials');
            }
        } catch (error) {
            set({ isLoading: false });
            throw error;
        }
    },

    logout: () => {
        set({
            user: null,
            isAuthenticated: false,
            isLoading: false,
        });
        localStorage.removeItem('auth-user');
    },

    register: async (userData: Omit<User, 'id' | 'createdAt'>) => {
        set({ isLoading: true });

        try {
            // Simulate API call
            await new Promise(resolve => setTimeout(resolve, 1000));

            const newUser: User = {
                ...userData,
                id: Math.random().toString(36).substr(2, 9),
                createdAt: new Date(),
            };

            set({
                user: newUser,
                isAuthenticated: true,
                isLoading: false,
            });
            localStorage.setItem('auth-user', JSON.stringify(newUser));
        } catch (error) {
            set({ isLoading: false });
            throw error;
        }
    },
}));

// Initialize auth state from localStorage
const initializeAuth = () => {
    const storedUser = localStorage.getItem('auth-user');
    if (storedUser) {
        try {
            const user = JSON.parse(storedUser);
            useAuthStore.setState({
                user,
                isAuthenticated: true,
            });
        } catch (error) {
            localStorage.removeItem('auth-user');
        }
    }
};

// Only run in browser
if (typeof window !== 'undefined') {
    initializeAuth();
}
